prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?orgId
  (SAMPLE(?orgLabel) AS ?orgLabel)
  ?modelId
  ?modelName
  (MIN(?created) AS ?earliestCreated)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created ;
         tai:originalId ?modelId ;
         bbo:name ?modelName .
  OPTIONAL { ?org rdfs:label ?orgLabel . }
  BIND(?created AS ?created)
}
GROUP BY ?orgId ?modelId ?modelName
ORDER BY ASC(?earliestCreated)
LIMIT 1

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?orgId
  (SAMPLE(?orgLabel) AS ?orgLabel)
  ?modelId
  (SAMPLE(?modelName) AS ?modelName)
  (MIN(?created) AS ?earliestCreated)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created ;
         tai:originalId ?modelId ;
         bbo:name ?modelName .
  OPTIONAL { ?org rdfs:label ?orgLabel . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
}
GROUP BY ?orgId ?modelId
ORDER BY ASC(?earliestCreated)
LIMIT 1

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?org
  ?orgLabel
  ?model
  ?modelName
  ?earliestCreated
WHERE {
  {
    SELECT (MIN(?created) AS ?earliestCreated)
    WHERE {
      ?model a bboExt:Model ;
             tai:modelCreated ?created .
    }
  }
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:modelCreated ?earliestCreated ;
         bbo:name ?modelName .
  OPTIONAL { ?org rdfs:label ?orgLabel . }
}
LIMIT 25
